import httpx, time, os

RUNWAY_KEY = os.environ["RUNWAY_API_KEY"]

def generate_video(prompt: str, image_url: str | None = None) -> str:
    """Submit generation job, poll until done, return video URL."""
    payload = {"prompt": prompt, "model": "gen3a_turbo", "duration": 5}
    if image_url:
        payload["image_as_end_frame"] = False
        payload["init_image"] = image_url

    r = httpx.post(
        "https://api.dev.runwayml.com/v1/image_to_video",
        headers={"Authorization": f"Bearer {RUNWAY_KEY}"},
        json=payload, timeout=30
    )
    job_id = r.json()["id"]

    for _ in range(60):  # max 10 minutes
        time.sleep(10)
        status = httpx.get(
            f"https://api.dev.runwayml.com/v1/tasks/{job_id}",
            headers={"Authorization": f"Bearer {RUNWAY_KEY}"}
        ).json()
        if status["status"] == "SUCCEEDED":
            return status["output"][0]
        if status["status"] == "FAILED":
            raise RuntimeError(f"Video generation failed: {status.get('failure')}")
    raise TimeoutError("Video generation timed out after 10 minutes")

import asyncio, httpx, subprocess from pathlib import Path
async def fetch_clip(url: str, out_path: str) -> None: async with httpx.AsyncClient() as client: r = await client.get(url) Path(out_path).write_bytes(r.content)
def concat_clips(paths: list[str], output: str) -> None: list_file = "concat_list.txt" with open(list_file, "w") as f: for p in paths: f.write(f"file '{p}'\n") subprocess.run( ["ffmpeg", "-f", "concat", "-safe", "0", "-i", list_file, "-c", "copy", output, "-y"], check=True )
